content.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
.chip-toolbar { padding: 10px 16px; background: #fff; border-radius: 12px; border: 1px solid #e5e7eb; margin-bottom: 12px; font-size: 12px; color: #6b7280; display: flex; align-items: center; flex-wrap: wrap; gap: 4px; }
.chip { display: inline-block; padding: 4px 12px; margin: 0 2px; border-radius: 14px; background: #f3f4f6; color: #4b5563; cursor: pointer; transition: all 0.15s; font-size: 12px; user-select: none; }
.chip:hover { background: #e5e7eb; }
.chip.active { background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); color: #fff; font-weight: 600; }
html, body { font-family: -apple-system, "PingFang SC", "Microsoft YaHei", sans-serif; background: #faf7f2; color: #1f2937; height: 100%; }
#dash-root { padding: 16px; min-height: 100vh; }
.dash-loading { color: #6b7280; padding: 32px; text-align: center; }
.dash-header { margin-bottom: 16px; }
.dash-title { font-size: 20px; font-weight: 600; color: #1f2937; }
.dash-sub { font-size: 12px; color: #6b7280; margin-top: 4px; }
.kpi-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 14px; }
.kpi-card { background: #ffffff; padding: 16px 18px; border-radius: 12px; border: 1px solid #e5e7eb; box-shadow: 0 1px 2px rgba(15,23,42,0.04); position: relative; overflow: hidden; }
.kpi-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 8px; letter-spacing: 0.3px; }
.kpi-value { font-size: 28px; font-weight: 700; color: #111827; line-height: 1.1; font-variant-numeric: tabular-nums; }
.kpi-trend { font-size: 11px; color: #059669; margin-top: 6px; }
.kpi-trend.neutral { color: #6b7280; }
.kpi-trend.down { color: #dc2626; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.chart-card { background: #ffffff; border-radius: 12px; border: 1px solid #e5e7eb; padding: 14px 16px 10px; box-shadow: 0 1px 2px rgba(15,23,42,0.04); }
.chart-title { font-size: 13px; font-weight: 600; margin-bottom: 8px; color: #1f2937; display: flex; justify-content: space-between; align-items: center; }
.chart-title .tag { font-size: 10px; font-weight: 400; color: #6b7280; padding: 2px 6px; background: #f3f4f6; border-radius: 4px; }
.chart-body { width: 100%; height: 260px; }
.chart-body.h180 { height: 180px; }
.chart-body.h320 { height: 320px; }
table.dash-tbl { width: 100%; border-collapse: collapse; font-size: 12px; }
table.dash-tbl th { text-align: left; padding: 6px 10px; color: #6b7280; font-weight: 500; border-bottom: 1px solid #e5e7eb; font-size: 10px; letter-spacing: 0.3px; text-transform: uppercase; }
table.dash-tbl td { padding: 8px 10px; border-bottom: 1px solid #f3f4f6; color: #374151; }
table.dash-tbl tr:hover td { background: #fafaf7; }
.tag-pri { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }
.tag-pri.P0 { background: #fee2e2; color: #dc2626; }
.tag-pri.P1 { background: #fef3c7; color: #d97706; }
.tag-pri.P2 { background: #dbeafe; color: #2563eb; }
.tag-risk { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-risk.高风险 { background: #fee2e2; color: #dc2626; }
.tag-risk.中风险 { background: #fef3c7; color: #d97706; }
.tag-risk.正常 { background: #d1fae5; color: #059669; }
.tag-role { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-role.金牌导购 { background: #fef3c7; color: #d97706; }
.tag-role.普通导购 { background: #e5e7eb; color: #4b5563; }
.tag-role.新人导购 { background: #ddd6fe; color: #7c3aed; }
.tag-role.店长 { background: #d1fae5; color: #059669; }

/* ========== 移动端响应式 (BI ?pageRenderType=phoneView) ========== */
@media (max-width: 768px) {
  html, body { height: auto !important; overflow-y: auto !important; }
  #dash-root { padding: 10px; overflow-y: auto; -webkit-overflow-scrolling: touch; } /* iframe-mobile-scroll */
  .dash-header { margin-bottom: 10px; }
  .dash-title { font-size: 16px; }
  .dash-sub { font-size: 11px; }
  .kpi-row, .grid-2, .grid-3 { grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 10px !important; }
  .kpi-card { padding: 10px 12px; border-radius: 8px; }
  .kpi-label { font-size: 10px; margin-bottom: 4px; }
  .kpi-value { font-size: 18px; }
  .kpi-trend { font-size: 10px; }
  .chart-card { padding: 10px 12px 6px; border-radius: 8px; }
  .chart-title { font-size: 12px; margin-bottom: 6px; }
  .chart-title .tag { font-size: 9px; padding: 1px 4px; }
  .chart-body { height: 200px !important; }
  .chart-body.h180 { height: 160px !important; }
  .chart-body.h220 { height: 180px !important; }
  .chart-body.h320 { height: 240px !important; }
  table.dash-tbl { font-size: 11px; }
  table.dash-tbl th { font-size: 9px; padding: 4px 6px; }
  table.dash-tbl td { padding: 5px 6px; }
  .chip-toolbar { padding: 6px 8px; font-size: 10px; gap: 2px; }
  .chip { padding: 3px 8px; font-size: 10px; margin: 0; }
}
@media (max-width: 480px) {
  .kpi-row { grid-template-columns: 1fr 1fr !important; }
  .grid-2 { grid-template-columns: 1fr !important; }
  .kpi-value { font-size: 16px; }
  .chart-body { height: 180px !important; }
  .chart-body.h180 { height: 150px !important; }
  .chart-body.h320 { height: 220px !important; }
}

content.script:
// === [auto-injected] chip toolbar (v2.1.9 §15.3) ===
(function autoBootstrap(){
  setTimeout(function(){
    try{
      var root=document.getElementById('dash-root');
      if(!root||root.innerText.indexOf('加载中')<0)return;
      fetch(window.parent.location.origin+'/api/card/tde662165a83e2b558a1c613/data',{
        method:'POST',headers:{'Content-Type':'application/json'},body:'{}',credentials:'include',
      }).then(function(r){return r.json();}).then(function(j){
        if(!j.viewData)return;
        var data=j.viewData.map(function(v){return v.chartMain.columns;});
        window.__rawData=data;
        if(typeof renderChart==='function')renderChart(data,function(){},{});
      });
    }catch(e){console.error('autoBootstrap fail:',e);}
  },4000);
})();

var ALL_TYPES=['商场店','社区店','写字楼店','交通店','学校店','夜市店','外卖卫星店','旗舰店','快取店'];
var activeType='ALL';
function changeType(t){activeType=t;if(window.__rawData)renderChart(window.__rawData,function(){},{});}
function renderToolbar(){
  var chips='<span class="chip '+(activeType==='ALL'?'active':'')+'" onclick="changeType(\'ALL\')">全部 (1200)</span>';
  ALL_TYPES.forEach(function(t){
    chips+='<span class="chip '+(activeType===t?'active':'')+'" onclick="changeType(\''+t+'\')">'+t+'</span>';
  });
  return '<div class="chip-toolbar">📍 门店类型: '+chips+'</div>';
}
function filterDataByType(data,t){
  if(t==='ALL')return data;
  return data.map(function(view){
    if(!view||!view.length)return view;
    var typeCol=null;
    for(var i=0;i<view.length;i++){if(view[i].name==='门店类型'){typeCol=view[i];break;}}
    if(!typeCol)return view;
    var keepIdx=[];
    for(var i=0;i<typeCol.data.length;i++){if(typeCol.data[i]===t)keepIdx.push(i);}
    return view.map(function(col){
      return {name:col.name,type:col.type,data:keepIdx.map(function(i){return col.data[i];})};
    });
  });
}
// === end injection ===

/**
 * 看板 08 — 加盟商单店报告 (规划 §10.7)
 * 给加盟商看的报告: 同侪比较 + 回本进度 + 总部支持
 * 5 dataViews:
 *   dv1: 合作状态汇总 (3-4 行: 合作状态 / 营收 / 利润率 / 门店数 / 加盟商数)
 *   dv2: 本店位置标签分布 (5 行: 顶部/中上/中位/中下/尾部)
 *   dv3: 回本风险等级 (4 行: 严重/预警/关注/健康)
 *   dv4: 加盟商类型分布 (4 行: 个体/区域代理/集团/投资公司)
 *   dv5: 城市层级 × 店型 (~30 行)
 */
(function autoBootstrap() {
  setTimeout(function() {
    try {
      var root = document.getElementById('dash-root');
      if (!root || root.innerText.indexOf('加载中') < 0) return;
      var cdId = 'tde662165a83e2b558a1c613';
      fetch(window.parent.location.origin + '/api/card/' + cdId + '/data', {
        method: 'POST', headers: {'Content-Type': 'application/json'}, body: '{}',
        credentials: 'include',
      }).then(function(r){return r.json();}).then(function(j) {
        if (!j.viewData) return;
        var data = j.viewData.map(function(v){return v.chartMain.columns;});
        if (typeof renderChart === 'function') renderChart(data, function(){}, {});
      });
    } catch(e) { console.error('autoBootstrap fail:', e); }
  }, 5000);
})();

function fmtNum(v) {
  if (v == null || isNaN(v)) return "—";
  v = Number(v);
  if (Math.abs(v) >= 1e8) return (v / 1e8).toFixed(2) + " 亿";
  if (Math.abs(v) >= 1e4) return (v / 1e4).toFixed(1) + " 万";
  return Math.round(v).toLocaleString();
}
function fmtPct(v, p) {
  if (v == null || isNaN(v)) return "—";
  return (Number(v) * 100).toFixed(p == null ? 1 : p) + "%";
}
function getCol(view, name) {
  if (!view) return null;
  for (var i = 0; i < view.length; i++) {
    if (view[i] && view[i].name === name) return view[i];
  }
  return null;
}
function sumCol(view, name) {
  var c = getCol(view, name);
  if (!c || !c.data) return 0;
  var s = 0;
  for (var k = 0; k < c.data.length; k++) s += Number(c.data[k] || 0);
  return s;
}
function avgCol(view, name) {
  var c = getCol(view, name);
  if (!c || !c.data) return 0;
  var s = 0, n = 0;
  for (var k = 0; k < c.data.length; k++) {
    var v = Number(c.data[k]);
    if (!isNaN(v)) { s += v; n++; }
  }
  return n ? s / n : 0;
}

function renderChart(data, clickFunc, config) {
  var root = document.getElementById('dash-root');
  window.__rawData=data;data=filterDataByType(data,activeType);var toolbarHTML=renderToolbar();if (!root) return;
  if (!data || data.length < 4) {
    root.innerHTML = '<div class="dash-loading">No data (need 4+ dataViews, got ' + (data && data.length) + ')</div>';
    return;
  }

  // dv1 合作状态 KPI
  var dv1 = data[0];
  var totalRev = sumCol(dv1, "月营收");
  var totalCt = sumCol(dv1, "店面贡献利润");
  var avgCtRate = avgCol(dv1, "店面贡献利润率");
  var totalStores = sumCol(dv1, "门店ID");
  var totalFranchisees = sumCol(dv1, "加盟商ID");

  // 各合作状态分布
  var statusNames = (getCol(dv1, "合作状态") || {}).data || [];
  var statusStores = (getCol(dv1, "门店ID") || {}).data || [];
  var statusRev = (getCol(dv1, "月营收") || {}).data || [];

  // dv2 本店位置标签 (Top 25% / 中位 / Bottom 等)
  var dv2 = data[1];
  var posNames = (getCol(dv2, "本店位置标签") || {}).data || [];
  var posStores = (getCol(dv2, "门店ID") || {}).data || [];
  var posRev = (getCol(dv2, "月营收") || {}).data || [];
  var posCtRate = (getCol(dv2, "店面贡献利润率") || {}).data || [];

  var posOrder = ['顶部 Top 25%','中上 P50-P75','中位 ±10%','中下 P25-P50','尾部 Bottom 25%'];
  var posColors = {'顶部 Top 25%':'#059669','中上 P50-P75':'#2563eb','中位 ±10%':'#9333ea','中下 P25-P50':'#d97706','尾部 Bottom 25%':'#dc2626'};

  // dv3 回本风险等级
  var dv3 = data[2];
  var riskNames = (getCol(dv3, "回本风险等级") || {}).data || [];
  var riskStores = (getCol(dv3, "门店ID") || {}).data || [];
  var riskPayback = (getCol(dv3, "累计回本率") || {}).data || [];
  var riskColors = {'健康':'#059669','关注':'#d97706','预警':'#9333ea','严重':'#dc2626'};

  // dv4 加盟商类型
  var dv4 = data[3];
  var typeNames = (getCol(dv4, "加盟商类型") || {}).data || [];
  var typeFs = (getCol(dv4, "加盟商ID") || {}).data || [];
  var typeRev = (getCol(dv4, "月营收") || {}).data || [];
  var typeCtRate = (getCol(dv4, "店面贡献利润率") || {}).data || [];

  // dv5 城市层级 × 店型
  var dv5 = data[4] || [];
  var tierNames = (getCol(dv5, "城市层级") || {}).data || [];
  var storeTypes = (getCol(dv5, "门店类型") || {}).data || [];
  var tsStores = (getCol(dv5, "门店ID") || {}).data || [];
  var tsRev = (getCol(dv5, "月营收") || {}).data || [];
  var tsCtRate = (getCol(dv5, "店面贡献利润率") || {}).data || [];
  var tsMedian = (getCol(dv5, "城市同店型_利润率_中位数") || {}).data || [];

  // 按城市层级聚合 (一线/新一线/二线/三线 4 行)
  var tierAgg = {};
  for (var i = 0; i < tierNames.length; i++) {
    var t = tierNames[i];
    if (!t) continue;
    if (!tierAgg[t]) tierAgg[t] = { stores: 0, rev: 0, ct: 0, n: 0 };
    tierAgg[t].stores += Number(tsStores[i] || 0);
    tierAgg[t].rev += Number(tsRev[i] || 0) * Number(tsStores[i] || 0);
    tierAgg[t].ct += Number(tsCtRate[i] || 0);
    tierAgg[t].n++;
  }
  var tierList = Object.keys(tierAgg);
  var tierLabels = tierList;
  var tierStoresArr = tierList.map(function(t){return tierAgg[t].stores;});
  var tierAvgRev = tierList.map(function(t){return tierAgg[t].stores > 0 ? tierAgg[t].rev / tierAgg[t].stores : 0;});
  var tierAvgCt = tierList.map(function(t){return tierAgg[t].n > 0 ? tierAgg[t].ct / tierAgg[t].n : 0;});

  // 渲染
  root.innerHTML = (
    toolbarHTML+
    '<div class="dash-header">' +
      '<div class="dash-title">📋 加盟商单店报告</div>' +
      '<div class="dash-sub">同侪比较 · ' + totalFranchisees + ' 加盟商 · ' + totalStores + ' 门店 · 加盟招商 / 督导视角</div>' +
    '</div>' +

    '<div class="kpi-row">' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">加盟商总数</div>' +
        '<div class="kpi-value">' + totalFranchisees + '</div>' +
        '<div class="kpi-trend neutral">' + totalStores + ' 家加盟门店</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">加盟体系总营收</div>' +
        '<div class="kpi-value">' + fmtNum(totalRev) + '</div>' +
        '<div class="kpi-trend">本期累计</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">加盟店均贡献利润率</div>' +
        '<div class="kpi-value">' + fmtPct(avgCtRate) + '</div>' +
        '<div class="kpi-trend' + (avgCtRate >= 0.15 ? '' : ' down') + '">' + (avgCtRate >= 0.15 ? '健康' : '需关注') + '</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">总部本期收益</div>' +
        '<div class="kpi-value">' + fmtNum(totalCt * 0.06) + '</div>' +
        '<div class="kpi-trend neutral">流水抽成 + 供应链</div>' +
      '</div>' +
    '</div>' +

    '<div class="grid-2">' +
      '<div class="chart-card">' +
        '<div class="chart-title">本店相对同侪定位<span class="tag">同城同店型对标</span></div>' +
        '<div id="chart-pos" class="chart-body h180"></div>' +
      '</div>' +
      '<div class="chart-card">' +
        '<div class="chart-title">回本风险等级分布<span class="tag">招商决策</span></div>' +
        '<div id="chart-risk" class="chart-body h180"></div>' +
      '</div>' +
    '</div>' +

    '<div class="grid-2">' +
      '<div class="chart-card">' +
        '<div class="chart-title">加盟商类型 × 平均利润率<span class="tag">招商结构</span></div>' +
        '<div id="chart-ftype" class="chart-body h180"></div>' +
      '</div>' +
      '<div class="chart-card">' +
        '<div class="chart-title">城市层级 × 加盟店均营收<span class="tag">区域对标</span></div>' +
        '<div id="chart-tier" class="chart-body h180"></div>' +
      '</div>' +
    '</div>' +

    '<div class="chart-card">' +
      '<div class="chart-title">合作状态分布<span class="tag">续约预警</span></div>' +
      '<table class="dash-tbl">' +
        '<thead><tr><th>合作状态</th><th>加盟门店数</th><th>占比</th><th>累计营收</th><th>建议动作</th></tr></thead>' +
        '<tbody>' +
          statusNames.map(function(s, i) {
            var n = Number(statusStores[i] || 0);
            var r = Number(statusRev[i] || 0);
            var pct = totalStores > 0 ? n / totalStores : 0;
            var action = '正常续约 + 标准支持';
            if (s === '续约预警') action = '加强督导 + 专项补贴';
            else if (s === '关注名单') action = '高频督导 + 定制方案';
            else if (s === '纠纷处理') action = '法务介入 + 协商解决';
            return '<tr><td>' + s + '</td><td>' + n + '</td><td>' + fmtPct(pct) +
              '</td><td>' + fmtNum(r) + '</td><td style="font-size:11px;">' + action + '</td></tr>';
          }).join('') +
        '</tbody>' +
      '</table>' +
    '</div>'
  );

  // ECharts
  var posData = posOrder.map(function(name) {
    var idx = posNames.indexOf(name);
    return idx >= 0 ? { name: name, value: Number(posStores[idx] || 0), itemStyle: { color: posColors[name] } } : null;
  }).filter(Boolean);
  echarts.init(document.getElementById('chart-pos')).setOption({
    tooltip: { trigger: 'item', formatter: '{b}: {c} 店月 ({d}%)' },
    legend: { bottom: 0, textStyle: { fontSize: 10 }, type: 'scroll' },
    series: [{ type: 'pie', radius: ['35%', '65%'], center: ['50%', '45%'],
      label: { fontSize: 10, formatter: '{b}\n{d}%' },
      data: posData,
    }],
  });

  var riskData = ['健康','关注','预警','严重'].map(function(r){
    var idx = riskNames.indexOf(r);
    return { name: r, value: idx >= 0 ? Number(riskStores[idx] || 0) : 0, itemStyle: { color: riskColors[r] } };
  });
  echarts.init(document.getElementById('chart-risk')).setOption({
    tooltip: { trigger: 'axis', formatter: function(p) { return p[0].name + ': ' + p[0].value + ' 门店'; }},
    grid: { left: 60, right: 30, top: 20, bottom: 25 },
    xAxis: { type: 'category', data: ['健康','关注','预警','严重'], axisLabel: { fontSize: 11 } },
    yAxis: { type: 'value', axisLabel: { fontSize: 10 } },
    series: [{
      type: 'bar', data: riskData,
      label: { show: true, position: 'top', fontSize: 11 },
    }],
  });

  // 加盟商类型 双轴: 营收 + 利润率
  echarts.init(document.getElementById('chart-ftype')).setOption({
    tooltip: { trigger: 'axis' },
    legend: { top: 0, textStyle: { fontSize: 10 } },
    grid: { left: 60, right: 60, top: 25, bottom: 25 },
    xAxis: { type: 'category', data: typeNames, axisLabel: { fontSize: 10 } },
    yAxis: [
      { type: 'value', name: '营收', axisLabel: { formatter: fmtNum, fontSize: 10 } },
      { type: 'value', name: '利润率', axisLabel: { formatter: function(v){return (v*100).toFixed(0)+'%';}, fontSize: 10 } },
    ],
    series: [
      { name: '总营收', type: 'bar', data: typeRev.map(Number), itemStyle: { color: '#2563eb' } },
      { name: '平均贡献利润率', type: 'line', yAxisIndex: 1, data: typeCtRate.map(Number),
        itemStyle: { color: '#d97706' }, lineStyle: { width: 2.5 },
        label: { show: true, fontSize: 10, formatter: function(p){return (p.value*100).toFixed(1)+'%';} },
      },
    ],
  });

  // 城市层级 双轴: 店均营收 + 平均利润率
  echarts.init(document.getElementById('chart-tier')).setOption({
    tooltip: { trigger: 'axis' },
    legend: { top: 0, textStyle: { fontSize: 10 } },
    grid: { left: 60, right: 60, top: 25, bottom: 25 },
    xAxis: { type: 'category', data: tierLabels, axisLabel: { fontSize: 11 } },
    yAxis: [
      { type: 'value', name: '店均营收', axisLabel: { formatter: fmtNum, fontSize: 10 } },
      { type: 'value', name: '利润率', axisLabel: { formatter: function(v){return (v*100).toFixed(0)+'%';}, fontSize: 10 } },
    ],
    series: [
      { name: '店均营收', type: 'bar', data: tierAvgRev.map(function(v){return Math.round(v);}), itemStyle: { color: '#2563eb' } },
      { name: '平均利润率', type: 'line', yAxisIndex: 1, data: tierAvgCt.map(Number),
        itemStyle: { color: '#059669' }, lineStyle: { width: 2.5 },
        label: { show: true, fontSize: 10, formatter: function(p){return (p.value*100).toFixed(1)+'%';} },
      },
    ],
  });

  window.addEventListener('resize', function() {
    ['chart-pos','chart-risk','chart-ftype','chart-tier'].forEach(function(id) {
      var el = document.getElementById(id);
      if (el && echarts.getInstanceByDom(el)) echarts.getInstanceByDom(el).resize();
    });
  });
}
